import{_ as a,o as r,c as o,a1 as e}from"./chunks/framework.BX4nIuL2.js";const c=JSON.parse('{"title":"Build group  and project","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/1projectmanage/buildgroup.md","filePath":"courses/fab-course/doc/1projectmanage/buildgroup.md"}'),i={name:"courses/fab-course/doc/1projectmanage/buildgroup.md"};function u(g,t,b,l,p,s){return r(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="build-group-and-project" tabindex="-1">Build group and project <a class="header-anchor" href="#build-group-and-project" aria-label="Permalink to &quot;Build group  and project&quot;">​</a></h1><p>This document is used to maintain the gitlab. The aim of <a href="https://docs.gitlab.com/ee/user/group/subgroups/" target="_blank" rel="noreferrer">&quot;group&quot;</a>and <a href="https://docs.gitlab.com/ee/user/project/" target="_blank" rel="noreferrer">&quot;project&quot; </a>is used to maintain our project</p><h2 id="_1-build-group" tabindex="-1">1 Build group <a class="header-anchor" href="#_1-build-group" aria-label="Permalink to &quot;1 Build group&quot;">​</a></h2><h4 id="_1-register" tabindex="-1">1.Register <a class="header-anchor" href="#_1-register" aria-label="Permalink to &quot;1.Register&quot;">​</a></h4><ul><li>Go to gitlab.com and register;</li><li>Sign in</li><li>Choice Group-Your Group in the upper left corner</li></ul><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/gitlab1.png" alt=""></p><p>2.Build group 目前计划的几个基础板块内容为</p><ul><li>manageproject:此处用于存放管理员使用的文档资料；（不放到gitbook上）</li><li>guide-book：此处有公开的所有参考文档，便于交流学习；（需要放到web页面上，形式类似gitbook）</li><li>safety：此组会存放各种安全相关的文档内容；（需要放到web页面上，形式类似gitbook）</li><li>hardware：此组存放各种相关设备的电子版信息</li><li>fab-01/student1 此组分配给fab第一期的第一个学生，以此类推（需要放到web页面上，形式类似gitbook）</li></ul><p>其他内容会根据实际情况变动 <img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/gitlab2.png" alt=""></p><h3 id="二、建立project" tabindex="-1">二、建立project <a class="header-anchor" href="#二、建立project" aria-label="Permalink to &quot;二、建立project&quot;">​</a></h3><p>在fab01（fab第一期）培训中加入学生 &quot;bob&#39;s fab&quot;, 通过邮件邀请bob <img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/gitlab11.png" alt=""></p><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/gitlab12.png" alt=""><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/gitlab13.png" alt=""><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/gitlab14.png" alt=""><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/gitlab15.png" alt=""><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/gitlab8.png" alt=""><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/gitlab17.png" alt=""></p><h3 id="三、删除组和project" tabindex="-1">三、删除组和project <a class="header-anchor" href="#三、删除组和project" aria-label="Permalink to &quot;三、删除组和project&quot;">​</a></h3><p>此处以删除build project为例</p><p>1.选择setting <img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/gitlab18.png" alt=""></p><p>2.拉到页面最下方 在path，transfer，remove 处选择“expand” <img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/gitlab19.png" alt=""></p><p>3.拉到页面最下方选择remove project， 并在文本框打入对应文字，右键confirm完成删除 <img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/gitlab20.png" alt=""><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/gitlab21.png" alt=""></p><h3 id="四、参考文档" tabindex="-1">四、参考文档 <a class="header-anchor" href="#四、参考文档" aria-label="Permalink to &quot;四、参考文档&quot;">​</a></h3><ul><li><a href="https://docs.gitlab.com/ee/user/group/subgroups/" target="_blank" rel="noreferrer">subgroup/gitlab</a></li></ul>',19)])])}const h=a(i,[["render",u]]);export{c as __pageData,h as default};
